module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

reg [15:0] partial_products [7:0];
reg [7:0] shift_reg;
reg [3:0] i;

always @(*) begin
    shift_reg = B;
    product = 0;
    for (i = 0; i < 8; i = i + 1) begin
        if (shift_reg[0] == 1)
            partial_products[i] = A << i;
        else
            partial_products[i] = 0;
        shift_reg = shift_reg >> 1;
    end
    for (i = 0; i < 8; i = i + 1)
        product = product + partial_products[i];
end

endmodule
